  // UnconfirmedEmailFailure の場合は自動的に resendCode を実行
  // これにより複数アカウントのサインアップ時に発生する `pendingUserId` 不整合問題を解決
  //
  // 発生シナリオ
  // 1. email1/password1/birthday1 でサインアップ（setPendingUserId に email1 の userId）
  // 2. メール未検証のまま戻る
  // 3. email2/password2/birthday2 でサインアップ（setPendingUserId に email2 の userId）
  // 4. email2 はメール検証してログイン ( setPendingUserId が null になる)
  // 5. email2 でログアウト
  // 6. email1 でログイン試行
  // 7. UnconfirmedEmailFailure を検知し、コード入力画面へ遷移
  // 8. コード入力画面で古い確認コードを入力し次へ
  // 9. lib/data/clients/auth/auth_client.dart の completeSignUp で assert(userId != null) により Exception が発生 (completeSignUp 時にはその user の userId が必要でそれを getPendingUserId から取得している)
  //
  // TODO: use_auth_code_operations.dart, login_state_controller.dart, auth_client.dart
  // の処理の流れが複雑なのでリファクタ
  if (res.hasLeft && res.left is UnconfirmedEmailFailure) {
    await resendCode();
  }

  // Refresh user's accessible contents after successful login
  if (res.hasRight && _mounted) {
    await ref
        .read(userAccessibleContentsControllerProvider.notifier)
        .refresh();
  }

  if (!_mounted) return res;
  state = res.fold((l) => AsyncValue.error(l, StackTrace.current),
      (r) => const AsyncValue.data(true));
  return res;
}

/// Sign out using Supabase auth
Future<Result<Failure, bool>> signOut() async {
  state = const AsyncValue.loading();
  final res = await _authClient.signOut();

  // Clear user's accessible contents after sign out
  if (_mounted) {
    ref.invalidate(userAccessibleContentsControllerProvider);
  }

  if (!_mounted) return res;
  state = res.fold((l) => AsyncValue.error(l, StackTrace.current),
      (r) => const AsyncValue.data(true));
  return res;
}

